function cleanTableCell(value) {
  return value
    .replace(/<br\s*\/?>/gi, " ")
    .replace(/<[^>]+>/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\|/g, "\\|");
}

function convertTables(value) {
  return value.replace(/<table[^>]*>([\s\S]*?)<\/table>/gi, (_table, body) => {
    const rows = [...body.matchAll(/<tr[^>]*>([\s\S]*?)<\/tr>/gi)].map((row) =>
      [...row[1].matchAll(/<td[^>]*>([\s\S]*?)<\/td>/gi)].map((cell) => cleanTableCell(cell[1]))
    );
    if (!rows.length) return "";
    const width = Math.max(...rows.map((row) => row.length));
    const normalized = rows.map((row) => Array.from({ length: width }, (_, index) => row[index] ?? ""));
    return "\n" + normalized
      .flatMap((row, index) => [
        "| " + row.join(" | ") + " |",
        ...(index === 0 ? ["| " + row.map(() => "---").join(" | ") + " |"] : []),
      ])
      .join("\n") + "\n";
  });
}

function normalizeNotionMarkdown(page) {
  let content = convertTables(page.raw);
  content = content
    .replace(/<callout[^>]*>\n?([\s\S]*?)\n?<\/callout>/gi, (_callout, body) =>
      "\n\n:::callout\n" + body.replace(/<br\s*\/?>/gi, "\n").replace(/^\t/gm, "").trim() + "\n:::\n\n"
    )
    .replace(/<file[^>]*><\/file>/gi, "\n_첨부 파일은 Notion 원문에서 확인하세요._\n")
    .replace(/<unknown\s+url="([^"]+)"[^>]*\/?>/gi, (_tag, url) => "[" + url + "](" + url + ")")
    .replace(/<synced_block_reference[^>]*>[\s\S]*?<\/synced_block_reference>/gi, "\n_공유되지 않은 동기화 블록은 Notion 원문에서 확인하세요._\n")
    .replace(/<empty-block\s*\/>/gi, "")
    .replace(/^\t/gm, "")
    .replace(/\\~/g, "~")
    .replace(/\s+\{color="[^"]+"\}$/gm, "")
    .replace(/\n{4,}/g, "\n\n\n")
    .trim();
  return "> 원문. [Notion](" + page.source + ")\n\n" + content + "\n";
}

function pageContent(page) {
  const protectedMarkdown = normalizeNotionMarkdown(page).replace(
    /```([^\n]*)\n([\s\S]*?)\n```/g,
    (_block, language, body) =>
      "```" + language + "\n" + body.replace(/</g, "%%NOTION_LT%%").replace(/>/g, "%%NOTION_GT%%") + "\n```"
  );
  const doc = markdownToTiptapDoc(protectedMarkdown);
  const restore = (node) => {
    if (typeof node.text === "string") {
      node.text = node.text.replace(/%%NOTION_LT%%/g, "<").replace(/%%NOTION_GT%%/g, ">");
    }
    for (const child of node.content ?? []) restore(child);
  };
  restore(doc);
  return JSON.stringify(doc);
}

function codeBlock(pageKey, includes) {
  const page = pageDefinitions.find((item) => item.key === pageKey);
  const blocks = [...page.raw.matchAll(/```[^\n]*\n([\s\S]*?)\n```/g)].map((match) => match[1].trim());
  const found = blocks.find((body) => body.includes(includes));
  if (!found) throw new Error(pageKey + "에서 프롬프트를 찾지 못했습니다: " + includes);
  return found;
}

